public int minFlipsMonoIncr(String s) {
    int flipCount = 0, oneCount = 0;
    for (char c : s.toCharArray()) {
        if (c == '1') {
            oneCount++;
        } else {
            flipCount = Math.min(flipCount + 1, oneCount);
        }
    }
    return flipCount;
}
```

